const express = require('express');
const Redis = require('ioredis');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const redis = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
});

const JWT_SECRET = process.env.JWT_SECRET || crypto.randomBytes(32).toString('hex');
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET || crypto.randomBytes(32).toString('hex');

// Security configurations
const ACCESS_TOKEN_EXPIRY = '15m';
const REFRESH_TOKEN_EXPIRY = 7 * 24 * 60 * 60; // 7 days in seconds (reduced from 1 year)
const REFRESH_TOKEN_ROTATION_ENABLED = true;
const REFRESH_TOKEN_REUSE_WINDOW = 10; // 10 seconds grace period for reuse detection

// Mock user database
const users = new Map([
  ['user1', { id: '1', username: 'user1', passwordHash: bcrypt.hashSync('password1', 10) }],
  ['user2', { id: '2', username: 'user2', passwordHash: bcrypt.hashSync('password2', 10) }],
]);

// Mock client database
const clients = new Map([
  ['client1', { id: 'client1', secret: bcrypt.hashSync('secret1', 10), redirectUris: ['http://localhost:3001/callback'] }],
]);

// Generate cryptographically secure random token
function generateSecureToken() {
  return crypto.randomBytes(32).toString('base64url');
}

// Store refresh token with metadata and family tracking
async function storeRefreshToken(userId, clientId, token, familyId = null) {
  const tokenId = crypto.randomBytes(16).toString('hex');
  const actualFamilyId = familyId || tokenId;
  
  const tokenData = {
    userId,
    clientId,
    tokenId,
    familyId: actualFamilyId,
    createdAt: Date.now(),
    used: false,
  };

  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
  
  await redis.setex(
    `refresh_token:${tokenHash}`,
    REFRESH_TOKEN_EXPIRY,
    JSON.stringify(tokenData)
  );

  await redis.setex(
    `token_family:${actualFamilyId}`,
    REFRESH_TOKEN_EXPIRY,
    JSON.stringify({ valid: true, userId, clientId })
  );

  return { tokenId, familyId: actualFamilyId };
}

// Invalidate entire token family on reuse detection
async function invalidateTokenFamily(familyId) {
  await redis.set(`token_family:${familyId}`, JSON.stringify({ valid: false, revokedAt: Date.now() }));
  
  const keys = await redis.keys('refresh_token:*');
  for (const key of keys) {
    const data = await redis.get(key);
    if (data) {
      const tokenData = JSON.parse(data);
      if (tokenData.familyId === familyId) {
        await redis.del(key);
      }
    }
  }
}

// Validate and consume refresh token with rotation
async function validateAndConsumeRefreshToken(token) {
  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
  const tokenDataStr = await redis.get(`refresh_token:${tokenHash}`);

  if (!tokenDataStr) {
    return { valid: false, error: 'invalid_token' };
  }

  const tokenData = JSON.parse(tokenDataStr);

  // Check if token family is still valid
  const familyDataStr = await redis.get(`token_family:${tokenData.familyId}`);
  if (!familyDataStr) {
    await redis.del(`refresh_token:${tokenHash}`);
    return { valid: false, error: 'invalid_token' };
  }

  const familyData = JSON.parse(familyDataStr);
  if (!familyData.valid) {
    await redis.del(`refresh_token:${tokenHash}`);
    return { valid: false, error: 'token_reused' };
  }

  // Check if token was already used (reuse detection)
  if (tokenData.used) {
    const timeSinceUse = Date.now() - tokenData.usedAt;
    
    // If used outside grace period, it's a reuse attack
    if (timeSinceUse > REFRESH_TOKEN_REUSE_WINDOW * 1000) {
      await invalidateTokenFamily(tokenData.familyId);
      return { valid: false, error: 'token_reused', familyRevoked: true };
    }
  }

  // Mark token as used
  tokenData.used = true;
  tokenData.usedAt = Date.now();
  await redis.setex(
    `refresh_token:${tokenHash}`,
    REFRESH_TOKEN_REUSE_WINDOW,
    JSON.stringify(tokenData)
  );

  return {
    valid: true,
    userId: tokenData.userId,
    clientId: tokenData.clientId,
    familyId: tokenData.familyId,
  };
}

// Generate access token
function generateAccessToken(userId, clientId) {
  return jwt.sign(
    { userId, clientId, type: 'access' },
    JWT_SECRET,
    { expiresIn: ACCESS_TOKEN_EXPIRY }
  );
}

