app.post('/oauth/authorize', async (req, res) => {
  const { client_id, redirect_uri, state, username, password, action } = req.body;

  if (action !== 'approve') {
    return res.redirect(`${redirect_uri}?error=access_denied&state=${state || ''}`);
  }

  const user = users.get(username);
  if (!user || !bcrypt.compareSync(password, user.passwordHash)) {
    return res.status(401).send('Invalid credentials');
  }

  const authCode = generateSecureToken();
  await redis.setex(
    `auth_code:${authCode}`,
    600,
    JSON.stringify({ userId: user.id, clientId: client_id, redirectUri: redirect_uri })
  );

  res.redirect(`${redirect_uri}?code=${authCode}&state=${state || ''}`);
});

// Token endpoint
app.post('/oauth/token', async (req, res) => {
  const { grant_type, code, refresh_token, client_id, client_secret, redirect_uri } = req.body;

  const client = clients.get(client_id);
  if (!client || !bcrypt.compareSync(client_secret, client.secret)) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (grant_type === 'authorization_code') {
    const authCodeData = await redis.get(`auth_code:${code}`);
    if (!authCodeData) {
      return res.status(400).json({ error: 'invalid_grant' });
    }

    const { userId, clientId, redirectUri } = JSON.parse(authCodeData);

    if (clientId !== client_id || redirectUri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant' });
    }

    await redis.del(`auth_code:${code}`);

    const accessToken = generateAccessToken(userId, clientId);
    const refreshToken = generateSecureToken();
    const { familyId } = await storeRefreshToken(userId, clientId, refreshToken);

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: 900,
      refresh_token: refreshToken,
    });
  } else if (grant_type === 'refresh_token') {
    const validation = await validateAndConsumeRefreshToken(refresh_token);

    if (!validation.valid) {
      if (validation.familyRevoked) {
        return res.status(401).json({ 
          error: 'invalid_grant', 
          error_description: 'Token reuse detected. All tokens in family revoked.' 
        });
      }
      return res.status(401).json({ error: 'invalid_grant' });
    }

    if (validation.clientId !== client_id) {
      await invalidateTokenFamily(validation.familyId);
      return res.status(401).json({ error: 'invalid_grant' });
    }

    const accessToken = generateAccessToken(validation.userId, validation.clientId);

    if (REFRESH_TOKEN_ROTATION_ENABLED) {
      const newRefreshToken = generateSecureToken();
      await storeRefreshToken(validation.userId, validation.clientId, newRefreshToken, validation.familyId);

      return res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 900,
        refresh_token: newRefreshToken,
      });
    } else {
      return res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 900,
      });
    }
  } else {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
});

